  private OpLessThanEquals() { super("<="); }
  public <ResType> ResType accept(BinOpVisitor<ResType> v) {
    return v.forOpLessThanEquals();
  }
}

class OpGreaterThanEquals extends BinOp {
  public static final OpGreaterThanEquals ONLY = new OpGreaterThanEquals();
  private OpGreaterThanEquals() { super(">="); }
  public <ResType> ResType accept(BinOpVisitor<ResType> v) {
    return v.forOpGreaterThanEquals();
  }
}

class OpAnd extends BinOp {
  public static final OpAnd ONLY = new OpAnd();
  private OpAnd() { super("&"); }
  public <ResType> ResType accept(BinOpVisitor<ResType> v) {
    return v.forOpAnd();
  }
}

class OpOr extends BinOp {
  public static final OpOr ONLY = new OpOr();
  private OpOr() { super("|"); }
  public <ResType> ResType accept(BinOpVisitor<ResType> v) {
    return v.forOpOr();
  }
}

/** BinOp for assignment operator '<-' */
class OpGets extends BinOp {
  public static final OpGets ONLY = new OpGets();
  private OpGets() { super("<-"); }
  public <ResType> ResType accept(BinOpVisitor<ResType> v) {
    return v.forOpGets();
  }
}

/* UnOpApp is a Term because it does not need enclosing parentheses when appearing in a binary expression */
class UnOpApp implements Term {
  private UnOp rator;
  private AST arg;

  UnOpApp(UnOp r, AST a) { rator = r; arg = a; }

  public UnOp rator() { return rator; }
  public AST arg() { return arg; }
  public <ResType> ResType accept(ASTVisitor<ResType> v) { return v.forUnOpApp(this); }
  public String toString() { return rator + " " + arg; }
}

class BinOpApp implements Term {
  private BinOp rator;
  private AST arg1, arg2;

  BinOpApp(BinOp r, AST a1, AST a2) { rator = r; arg1 = a1; arg2 = a2; }

  public BinOp rator() { return rator; }
  public AST arg1() { return arg1; }
  public AST arg2() { return arg2; }
  public <ResType> ResType accept(ASTVisitor<ResType> v) { return v.forBinOpApp(this); }
  public String toString() {
    return "(" + toString(arg1) + " " + rator + " " + toString(arg2) + ")";
  }
  private String toString(AST arg) {
    String argString = arg.toString();
    if (! (arg instanceof Term)) return "(" + argString + ")";
    else return argString;
  }
}

/** Map represents a lambda abstraction with typed parameters. */
class Map implements AST {
  private Variable[] vars;
  private JamType[] types;
  private AST body;

  /** Constructs a Map with typed parameters. */
  Map(Variable[] v, JamType[] t, AST b) { vars = v; types = t; body = b; }

  public Variable[] vars() { return vars; }
  public JamType[] types() { return types; }
  public AST body() { return body; }
  public <ResType> ResType accept(ASTVisitor<ResType> v) { return v.forMap(this); }
  public String toString() {
    StringBuilder sb = new StringBuilder("map ");
    for (int i = 0; i < vars.length; i++) {
      if (i > 0) sb.append(", ");
      sb.append(vars[i]);
      if (types != null && i < types.length && types[i] != null) {
        sb.append(" : ").append(types[i]);
      }
    }
    sb.append(" to ").append(body);
    return sb.toString();
  }
}

class App implements Term {
  private AST rator;
  private AST[] args;

  App(AST r, AST[] a) { rator = r; args = a; }

  public AST rator() { return rator; }
  public AST[] args() { return args; }

  public <ResType> ResType accept(ASTVisitor<ResType> v) { return v.forApp(this); }
  public String toString() {
    if ((rator instanceof PrimFun) || (rator instanceof Variable))
      return rator + "(" + ToString.toString(args,", ") + ")";
    else
      return "(" +  rator + ")(" + ToString.toString(args,", ") + ")";
  }
}

class If implements AST {
  private AST test, conseq, alt;
  If(AST t, AST c, AST a) { test = t; conseq = c; alt = a; }

  public AST test() { return test; }
  public AST conseq() { return conseq; }
  public AST alt() { return alt; }
  public <ResType> ResType accept(ASTVisitor<ResType> v) { return v.forIf(this); }
  public String toString() {
    return "if " + test + " then " + conseq + " else " + alt ;
  }
}

class Let implements AST {
  private Def[] defs;
  private AST body;
  Let(Def[] d, AST b) { defs = d; body = b; }

  public <ResType> ResType accept(ASTVisitor<ResType> v) { return v.forLet(this); }
  public Def[] defs() { return defs; }
  public AST body() { return body; }
  public String toString() {
    return "let " + ToString.toString(defs," ") + " in " + body;
  }

  /* Commonly used non-essential methods */
  /** Returns the vars that are locally defined in this Let. */
  public Variable[] vars() {
    int n = defs.length;
    Variable[] vars = new Variable[n];
    for(int i = 0; i < n; i++) { vars[i] = defs[i].lhs(); }
    return vars;
  }
  /** Returns the exps that appear on the rhs of defs in this Let. */
  public AST[] exps() {
    int n = defs.length;
    AST[] exps = new AST[n];
    for(int i = 0; i < n; i++) { exps[i] = defs[i].rhs(); }
    return exps;
  }
}

/** A Block is a non-empty sequence of statements (expressions) that returns the value of the last
  * statement (expression).  The preceding statements are included solely for their side-effect
  * (changes to the values stored in boxes)
  * Hence, a block cannot appear as the first argument in a binary operation unless it is
  * enclosed in parentheses. The empty block is a parser error (ParseException).
  */
class Block implements AST {
  private AST[] exps;
  public Block(AST[] es) {
    exps = es;
  }

  public <ResType> ResType accept(ASTVisitor<ResType> v) { return v.forBlock(this); }

  public AST[] exps() { return exps; }

  public String toString() {
    return "{" + ToString.toString(exps, "; ") + "}";
  }
}


/** Def class representing a typed definition embedded inside a Let. */
class Def {
  private Variable lhs;
  private JamType type;
  private AST rhs;

  /** Constructs a definition with a declared type for the variable. */
  Def(Variable l, JamType t, AST r) { lhs = l; type = t; rhs = r; }
  public Variable lhs() { return lhs; }
  /** Returns the declared type of this definition's variable. */
  public JamType type() { return type; }
  public AST rhs() { return rhs; }

  public String toString() { return lhs + " : " + type + " := " + rhs + ";"; }
}

/** Dummy class containing an improved toString method for arrays. */
class ToString {

  public static String toString(Object[] a, String s) {
    StringBuffer result = new StringBuffer();
    for (int i = 0; i < a.length; i++) {
      if (i > 0) result.append(s);
      Object elt = a[i];
      String eltString = (elt instanceof Object[]) ?
        toString((Object[]) elt, s) : elt.toString();
      result.append(eltString);
    }
    return result.toString();
  }
}

/* ===== Type Hierarchy for Typed Jam ===== */

/** The interface representing Jam types. */
interface JamType {}

/** Represents the integer type 'int'. */
class IntType implements JamType {
  public static final IntType ONLY = new IntType();
  private IntType() {}
  public boolean equals(Object o) { return o instanceof IntType; }
  public int hashCode() { return 1; }
  public String toString() { return "int"; }
}

/** Represents the boolean type 'bool'. */
class BoolType implements JamType {
  public static final BoolType ONLY = new BoolType();
  private BoolType() {}
  public boolean equals(Object o) { return o instanceof BoolType; }
  public int hashCode() { return 2; }
  public String toString() { return "bool"; }
}

/** Represents the unit type 'unit'. */
class UnitType implements JamType {
  public static final UnitType ONLY = new UnitType();
  private UnitType() {}
  public boolean equals(Object o) { return o instanceof UnitType; }
  public int hashCode() { return 3; }
  public String toString() { return "unit"; }
}

/** Represents the list type 'list T' for element type T. */
class ListType implements JamType {
  private JamType elem;
  ListType(JamType e) { elem = e; }
  public JamType elem() { return elem; }
  public boolean equals(Object o) {
    return (o instanceof ListType) && ((ListType)o).elem.equals(elem);
  }
  public int hashCode() { return 4 + elem.hashCode(); }
  public String toString() { return "list " + elem; }
}

/** Represents the reference type 'ref T' for element type T. */
class RefType implements JamType {
  private JamType elem;
  RefType(JamType e) { elem = e; }
  public JamType elem() { return elem; }
  public boolean equals(Object o) {
    return (o instanceof RefType) && ((RefType)o).elem.equals(elem);
  }
  public int hashCode() { return 5 + elem.hashCode(); }
  public String toString() { return "ref " + elem; }
}

/** Represents the function type '(T1, T2, ... -> T)'. */
class FunType implements JamType {
  private JamType[] params;
  private JamType result;
  FunType(JamType[] p, JamType r) { params = p; result = r; }
  public JamType[] params() { return params; }
  public JamType result() { return result; }
  public boolean equals(Object o) {
    if (!(o instanceof FunType)) return false;
    FunType other = (FunType) o;
    if (params.length != other.params.length) return false;
    for (int i = 0; i < params.length; i++) {
      if (!params[i].equals(other.params[i])) return false;
    }
    return result.equals(other.result);
  }
  public int hashCode() {
    int h = 6 + result.hashCode();
    for (JamType p : params) h += p.hashCode();
    return h;
  }
  public String toString() {
    StringBuilder sb = new StringBuilder("(");
    for (int i = 0; i < params.length; i++) {
      if (i > 0) sb.append(", ");
      sb.append(params[i]);
    }
    sb.append(" -> ");
    sb.append(result);
    sb.append(")");
    return sb.toString();
  }
}

/** A typed variable pairing an identifier with its declared type. Used during parsing. */
class TypedVariable {
  private Variable var;
  private JamType type;
  TypedVariable(Variable v, JamType t) { var = v; type = t; }
  public Variable var() { return var; }
  public JamType type() { return type; }
  public String toString() { return var + " : " + type; }
}

/** An empty constant annotated with its element type: 'empty : T'. */
class TypedEmptyConstant implements Constant {
  private JamType elemType;
  TypedEmptyConstant(JamType t) { elemType = t; }
  public JamType elemType() { return elemType; }
  public <T> T accept(ASTVisitor<T> v) { return v.forTypedEmptyConstant(this); }
  public String toString() { return "empty : " + elemType; }
}

